using Microsoft.EntityFrameworkCore;
using SiteInspector.Shared.Models;

namespace SiteInspector.Server.Data;

public class InspectorDbContext : DbContext
{
    public InspectorDbContext(DbContextOptions<InspectorDbContext> options) : base(options) { }

    public DbSet<InspectionReport> InspectionReports => Set<InspectionReport>();
    public DbSet<ChecklistItem> ChecklistItems => Set<ChecklistItem>();
    public DbSet<PhotoAttachment> PhotoAttachments => Set<PhotoAttachment>();
    public DbSet<ConstructionSite> ConstructionSites => Set<ConstructionSite>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<InspectionReport>(entity =>
        {
            entity.HasKey(e => e.Id);

            entity.HasMany(e => e.Items)
                .WithOne()
                .HasForeignKey("InspectionReportId")
                .OnDelete(DeleteBehavior.Cascade);

            entity.HasMany(e => e.Photos)
                .WithOne()
                .HasForeignKey("InspectionReportId")
                .OnDelete(DeleteBehavior.Cascade);

            entity.Property(e => e.Status).HasConversion<string>();
        });

        modelBuilder.Entity<ChecklistItem>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Severity).HasConversion<string>();
        });

        modelBuilder.Entity<PhotoAttachment>(entity =>
        {
            entity.HasKey(e => e.Id);
        });

        modelBuilder.Entity<ConstructionSite>(entity =>
        {
            entity.HasKey(e => e.Id);
        });
    }
}

