using Microsoft.EntityFrameworkCore;
using SiteInspector.Server.Data;
using SiteInspector.Shared.Models;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddDbContext<InspectorDbContext>(options =>
    options.UseSqlite("Data Source=siteinspector.db"));

builder.Services.AddCors(options =>
    options.AddDefaultPolicy(policy => policy.AllowAnyOrigin().AllowAnyMethod().AllowAnyHeader()));

var app = builder.Build();

using (var scope = app.Services.CreateScope())
{
    var db = scope.ServiceProvider.GetRequiredService<InspectorDbContext>();
    db.Database.EnsureCreated();
}

app.UseCors();
app.UseBlazorFrameworkFiles();
app.UseStaticFiles();

app.MapPost("/api/sync", async (SyncPayload payload, InspectorDbContext db) =>
{
    var result = new SyncResult { Success = true };
    try
    {
        foreach (var inspection in payload.Inspections)
        {
            var existing = await db.InspectionReports
                .Include(r => r.Items)
                .Include(r => r.Photos)
                .FirstOrDefaultAsync(r => r.Id == inspection.Id);

            if (existing is not null)
            {
                db.ChecklistItems.RemoveRange(existing.Items);
                db.PhotoAttachments.RemoveRange(existing.Photos);

                existing.SiteId = inspection.SiteId;
                existing.SiteName = inspection.SiteName;
                existing.InspectorName = inspection.InspectorName;
                existing.CreatedAt = inspection.CreatedAt;
                existing.CompletedAt = inspection.CompletedAt;
                existing.Notes = inspection.Notes;
                existing.Status = inspection.Status;
                existing.Items = inspection.Items;
                existing.Photos = inspection.Photos;
            }
            else
            {
                db.InspectionReports.Add(inspection);
            }
            result.SyncedIds.Add(inspection.Id);
        }
        await db.SaveChangesAsync();
    }
    catch (Exception ex)
    {
        result.Success = false;
        result.Errors.Add(ex.Message);
    }
    return Results.Ok(result);
});

app.MapGet("/api/inspections", async (InspectorDbContext db) =>
    await db.InspectionReports.Include(r => r.Items).Include(r => r.Photos).ToListAsync());

app.MapGet("/api/inspections/{id}", async (Guid id, InspectorDbContext db) =>
{
    var report = await db.InspectionReports
        .Include(r => r.Items)
        .Include(r => r.Photos)
        .FirstOrDefaultAsync(r => r.Id == id);
    return report is not null ? Results.Ok(report) : Results.NotFound();
});

app.MapGet("/api/sites", async (InspectorDbContext db) =>
    await db.ConstructionSites.ToListAsync());

app.MapPost("/api/sites", async (ConstructionSite site, InspectorDbContext db) =>
{
    db.ConstructionSites.Add(site);
    await db.SaveChangesAsync();
    return Results.Created($"/api/sites/{site.Id}", site);
});

app.MapFallbackToFile("index.html");

app.Run();

