using System.Net.Http.Json;
using SiteInspector.Shared.Models;

namespace SiteInspector.Client.Services;

public class SyncService : IAsyncDisposable
{
    private readonly HttpClient _httpClient;
    private readonly IndexedDbService _db;
    private readonly ConnectivityService _connectivity;
    private Timer? _timer;

    public int PendingCount { get; private set; }
    public event Action? OnSyncStatusChanged;

    public SyncService(HttpClient httpClient, IndexedDbService db, ConnectivityService connectivity)
    {
        _httpClient = httpClient;
        _db = db;
        _connectivity = connectivity;
    }

    public void StartAsync()
    {
        _timer = new Timer(async _ =>
        {
            try
            {
                await SyncAsync();
            }
            catch
            {
                // Silently handle sync errors; will retry on next tick
            }
        }, null, TimeSpan.Zero, TimeSpan.FromSeconds(30));
    }

    public async Task SyncAsync()
    {
        if (!_connectivity.IsOnline)
            return;

        var pending = await _db.GetAllAsync<InspectionReport>("syncQueue");
        PendingCount = pending.Count;
        OnSyncStatusChanged?.Invoke();

        if (pending.Count == 0)
            return;

        var payload = new SyncPayload { Inspections = pending };

        try
        {
            var response = await _httpClient.PostAsJsonAsync("/api/sync", payload);
            if (response.IsSuccessStatusCode)
            {
                var result = await response.Content.ReadFromJsonAsync<SyncResult>();
                if (result?.Success == true)
                {
                    foreach (var id in result.SyncedIds)
                    {
                        await _db.DeleteAsync("syncQueue", id.ToString());

                        var inspection = await _db.GetAsync<InspectionReport>("inspections", id.ToString());
                        if (inspection != null)
                        {
                            inspection.Status = InspectionStatus.Synced;
                            await _db.PutAsync("inspections", inspection);
                        }
                    }
                }

                PendingCount = (await _db.GetAllAsync<InspectionReport>("syncQueue")).Count;
                OnSyncStatusChanged?.Invoke();
            }
        }
        catch
        {
            // Network error; will retry on next tick
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_timer != null)
        {
            await _timer.DisposeAsync();
        }
    }
}

window.indexedDb = {
    _db: null,

    initialize: function () {
        return new Promise(function (resolve, reject) {
            if (window.indexedDb._db) {
                resolve();
                return;
            }
            var request = window.indexedDB.open("SiteInspectorDB", 1);
            request.onupgradeneeded = function (event) {
                var db = event.target.result;
                if (!db.objectStoreNames.contains("inspections")) {
                    db.createObjectStore("inspections", { keyPath: "id" });
                }
                if (!db.objectStoreNames.contains("sites")) {
                    db.createObjectStore("sites", { keyPath: "id" });
                }
                if (!db.objectStoreNames.contains("photos")) {
                    db.createObjectStore("photos", { keyPath: "id" });
                }
                if (!db.objectStoreNames.contains("syncQueue")) {
                    db.createObjectStore("syncQueue", { keyPath: "id" });
                }
            };
            request.onsuccess = function (event) {
                window.indexedDb._db = event.target.result;
                resolve();
            };
            request.onerror = function (event) {
                reject(event.target.error);
            };
        });
    },

    putItem: function (storeName, item) {
        return new Promise(function (resolve, reject) {
            var parsed = JSON.parse(item);
            var tx = window.indexedDb._db.transaction(storeName, "readwrite");
            var store = tx.objectStore(storeName);
            var request = store.put(parsed);
            request.onsuccess = function () { resolve(); };
            request.onerror = function (event) { reject(event.target.error); };
        });
    },

    getItem: function (storeName, id) {
        return new Promise(function (resolve, reject) {
            var tx = window.indexedDb._db.transaction(storeName, "readonly");
            var store = tx.objectStore(storeName);
            var request = store.get(id);
            request.onsuccess = function () {
                resolve(request.result ? JSON.stringify(request.result) : null);
            };
            request.onerror = function (event) { reject(event.target.error); };
        });
    },

    getAllItems: function (storeName) {
        return new Promise(function (resolve, reject) {
            var tx = window.indexedDb._db.transaction(storeName, "readonly");
            var store = tx.objectStore(storeName);
            var request = store.getAll();
            request.onsuccess = function () {
                resolve(JSON.stringify(request.result || []));
            };
            request.onerror = function (event) { reject(event.target.error); };
        });
    },

    deleteItem: function (storeName, id) {
        return new Promise(function (resolve, reject) {
            var tx = window.indexedDb._db.transaction(storeName, "readwrite");
            var store = tx.objectStore(storeName);
            var request = store.delete(id);
            request.onsuccess = function () { resolve(); };
            request.onerror = function (event) { reject(event.target.error); };
        });
    },

    clearStore: function (storeName) {
        return new Promise(function (resolve, reject) {
            var tx = window.indexedDb._db.transaction(storeName, "readwrite");
            var store = tx.objectStore(storeName);
            var request = store.clear();
            request.onsuccess = function () { resolve(); };
            request.onerror = function (event) { reject(event.target.error); };
        });
    }
};

