@@ -1,0 +1,91 @@
+using System.Net.Http.Json;
+using SiteInspector.Shared.Models;
+
+namespace SiteInspector.Client.Services;
+
+public class SyncService : IAsyncDisposable
+{
+    private readonly HttpClient _httpClient;
+    private readonly IndexedDbService _db;
+    private readonly ConnectivityService _connectivity;
+    private Timer? _timer;
+
+    public int PendingCount { get; private set; }
+    public event Action? OnSyncStatusChanged;
+
+    public SyncService(HttpClient httpClient, IndexedDbService db, ConnectivityService connectivity)
+    {
+        _httpClient = httpClient;
+        _db = db;
+        _connectivity = connectivity;
+    }
+
+    public void StartAsync()
+    {
+        _timer = new Timer(async _ =>
+        {
+            try
+            {
+                await SyncAsync();
+            }
+            catch
+            {
+                // Silently handle sync errors; will retry on next tick
+            }
+        }, null, TimeSpan.Zero, TimeSpan.FromSeconds(30));
+    }
+
+    public async Task SyncAsync()
+    {
+        if (!_connectivity.IsOnline)
+            return;
+
+        var pending = await _db.GetAllAsync<InspectionReport>("syncQueue");
+        PendingCount = pending.Count;
+        OnSyncStatusChanged?.Invoke();
+
+        if (pending.Count == 0)
+            return;
+
+        var payload = new SyncPayload { Inspections = pending };
+
+        try
+        {
+            var response = await _httpClient.PostAsJsonAsync("/api/sync", payload);
+            if (response.IsSuccessStatusCode)
+            {
+                var result = await response.Content.ReadFromJsonAsync<SyncResult>();
+                if (result?.Success == true)
+                {
+                    foreach (var id in result.SyncedIds)
+                    {
+                        await _db.DeleteAsync("syncQueue", id.ToString());
+
+                        var inspection = await _db.GetAsync<InspectionReport>("inspections", id.ToString());
+                        if (inspection != null)
+                        {
+                            inspection.Status = InspectionStatus.Synced;
+                            await _db.PutAsync("inspections", inspection);
+                        }
+                    }
+                }
+
+                PendingCount = (await _db.GetAllAsync<InspectionReport>("syncQueue")).Count;
+                OnSyncStatusChanged?.Invoke();
+            }
+        }
+        catch
+        {
+            // Network error; will retry on next tick
+        }
+    }
+
+    public async ValueTask DisposeAsync()
+    {
+        if (_timer != null)
+        {
+            await _timer.DisposeAsync();
+        }
+    }
+}
+

