6. public class SyncService : IAsyncDisposable
7. {
8.     private readonly HttpClient _httpClient;
9.     private readonly IndexedDbService _db;
10.     private readonly ConnectivityService _connectivity;
11.     private Timer? _timer;
12. 
13.     public int PendingCount { get; private set; }
