    public async Task InitializeAsync()
    {
        await _jsRuntime.InvokeVoidAsync("indexedDb.initialize");
    }

    public async Task PutAsync<T>(string storeName, T item)
    {
        var json = JsonSerializer.Serialize(item);
        await _jsRuntime.InvokeVoidAsync("indexedDb.putItem", storeName, json);
    }

    public async Task<T?> GetAsync<T>(string storeName, string id)
    {
        var json = await _jsRuntime.InvokeAsync<string?>("indexedDb.getItem", storeName, id);
        if (string.IsNullOrEmpty(json))
            return default;
        return JsonSerializer.Deserialize<T>(json);
    }

    public async Task<List<T>> GetAllAsync<T>(string storeName)
    {
        var json = await _jsRuntime.InvokeAsync<string>("indexedDb.getAllItems", storeName);
        if (string.IsNullOrEmpty(json))
            return new List<T>();
        return JsonSerializer.Deserialize<List<T>>(json) ?? new List<T>();
    }

    public async Task DeleteAsync(string storeName, string id)
    {
        await _jsRuntime.InvokeVoidAsync("indexedDb.deleteItem", storeName, id);
    }
}
