1. using System.Net.Http.Json;
2. using SiteInspector.Shared.Models;
3. 
4. namespace SiteInspector.Client.Services;
5. 
6. public class SyncService : IAsyncDisposable
7. {
8.     private readonly HttpClient _httpClient;
9.     private readonly IndexedDbService _db;
10.     private readonly ConnectivityService _connectivity;
11.     private Timer? _timer;
12. 
13.     public int PendingCount { get; private set; }
14.     public event Action? OnSyncStatusChanged;
15. 
16.     public SyncService(HttpClient httpClient, IndexedDbService db, ConnectivityService connectivity)
17.     {
18.         _httpClient = httpClient;
19.         _db = db;
20.         _connectivity = connectivity;
21.     }
22. 
23.     public void StartAsync()
24.     {
25.         _timer = new Timer(async _ =>
26.         {
27.             try
28.             {
29.                 await SyncAsync();
30.             }
31.             catch
32.             {
33.                 // Silently handle sync errors; will retry on next tick
34.             }
35.         }, null, TimeSpan.Zero, TimeSpan.FromSeconds(30));
36.     }
37. 
38.     public async Task SyncAsync()
39.     {
40.         if (!_connectivity.IsOnline)
41.             return;
42. 
43.         var pending = await _db.GetAllAsync<InspectionReport>("syncQueue");
44.         PendingCount = pending.Count;
45.         OnSyncStatusChanged?.Invoke();
46. 
47.         if (pending.Count == 0)
48.             return;
49. 
50.         var payload = new SyncPayload { Inspections = pending };
51. 
52.         try
53.         {
54.             var response = await _httpClient.PostAsJsonAsync("/api/sync", payload);
55.             if (response.IsSuccessStatusCode)
56.             {
57.                 var result = await response.Content.ReadFromJsonAsync<SyncResult>();
58.                 if (result?.Success == true)
59.                 {
60.                     foreach (var id in result.SyncedIds)
61.                     {
62.                         await _db.DeleteAsync("syncQueue", id.ToString());
63. 
64.                         var inspection = await _db.GetAsync<InspectionReport>("inspections", id.ToString());
65.                         if (inspection != null)
66.                         {
67.                             inspection.Status = InspectionStatus.Synced;
68.                             await _db.PutAsync("inspections", inspection);
69.                         }
70.                     }
71.                 }
72. 
73.                 PendingCount = (await _db.GetAllAsync<InspectionReport>("syncQueue")).Count;
74.                 OnSyncStatusChanged?.Invoke();
75.             }
76.         }
77.         catch
78.         {
79.             // Network error; will retry on next tick
80.         }
81.     }
82. 
83.     public async ValueTask DisposeAsync()
84.     {
85.         if (_timer != null)
86.         {
87.             await _timer.DisposeAsync();
88.         }
89.     }
90. }
91.

