@page "/"
@inject NavigationManager Navigation
@inject InspectionService InspectionService
@inject SyncService Sync
@inject ConnectivityService Connectivity
@implements IDisposable

<PageTitle>Home - Site Inspector</PageTitle>

<div class="dashboard">
    <section class="stats-row">
        <div class="stat-card">
            <span class="stat-card__value">@_draftCount</span>
            <span class="stat-card__label">Pending</span>
        </div>
        <div class="stat-card">
            <span class="stat-card__value">@_completedTodayCount</span>
            <span class="stat-card__label">Completed Today</span>
        </div>
        <div class="stat-card">
            <span class="stat-card__value">@Sync.PendingCount</span>
            <span class="stat-card__label">Awaiting Sync</span>
        </div>
    </section>

    <section class="dashboard__actions">
        <button class="btn btn--primary btn--large" @onclick="StartNewInspection">
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="16"/><line x1="8" y1="12" x2="16" y2="12"/></svg>
            New Inspection
        </button>
    </section>

    <section class="sync-status">
        <div class="sync-status__row">
            <span class="badge @(Connectivity.IsOnline ? "badge--green" : "badge--orange")">
                @(Connectivity.IsOnline ? "Online" : "Offline")
            </span>
            <span class="sync-status__text">@Sync.PendingCount items pending sync</span>
            <button class="btn btn--small btn--outline" @onclick="SyncNow" disabled="@(!Connectivity.IsOnline || _isSyncing)">
                @(_isSyncing ? "Syncing…" : "Sync Now")
            </button>
        </div>
    </section>

    <section class="recent-inspections">
        <h2 class="section-title">Recent Inspections</h2>
        @if (!_loaded)
        {
            <p class="loading-text">Loading…</p>
        }
        else if (_inspections.Count == 0)
        {
            <p class="empty-text">No inspections yet. Tap "New Inspection" to get started.</p>
        }
        else
        {
            @foreach (var inspection in _inspections)
            {
                <div class="inspection-card" @onclick="() => NavigateToInspection(inspection)">
                    <div class="inspection-card__header">
                        <span class="inspection-card__site">@inspection.SiteName</span>
                        <span class="badge @StatusBadgeClass(inspection.Status)">@inspection.Status</span>
                    </div>
                    <div class="inspection-card__meta">
                        <span>@inspection.InspectorName</span>
                        <span>@inspection.CreatedAt.ToLocalTime().ToString("MMM d, yyyy h:mm tt")</span>
                    </div>
                </div>
            }
        }
    </section>
</div>

@code {
    private List<InspectionReport> _inspections = new();
    private int _draftCount;
    private int _completedTodayCount;
    private bool _loaded;
    private bool _isSyncing;
    private bool _hasRendered;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && !_hasRendered)
        {
            _hasRendered = true;
            Sync.OnSyncStatusChanged += OnSyncStatusChanged;
            await LoadDataAsync();
            StateHasChanged();
        }
    }

    private async Task LoadDataAsync()
    {
        var all = await InspectionService.GetAllInspectionsAsync();
        _inspections = all.OrderByDescending(i => i.CreatedAt).ToList();
        _draftCount = all.Count(i => i.Status == InspectionStatus.Draft);
        var today = DateTime.UtcNow.Date;
        _completedTodayCount = all.Count(i => i.Status != InspectionStatus.Draft && i.CompletedAt?.Date == today);
        _loaded = true;
    }

    private void StartNewInspection()
    {
        Navigation.NavigateTo("/inspection/new");
    }

    private void NavigateToInspection(InspectionReport inspection)
    {
        if (inspection.Status == InspectionStatus.Draft)
            Navigation.NavigateTo($"/inspection/{inspection.Id}");
        else
            Navigation.NavigateTo($"/inspection/{inspection.Id}/detail");
    }

    private async Task SyncNow()
    {
        _isSyncing = true;
        StateHasChanged();
        try
        {
            await Sync.SyncAsync();
            await LoadDataAsync();
        }
        finally
        {
            _isSyncing = false;
            StateHasChanged();
        }
    }

    private string StatusBadgeClass(InspectionStatus status) => status switch
    {
        InspectionStatus.Draft => "badge--gray",
        InspectionStatus.Completed => "badge--blue",
        InspectionStatus.Synced => "badge--green",
        _ => ""
    };

    private void OnSyncStatusChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Sync.OnSyncStatusChanged -= OnSyncStatusChanged;
    }
}

