+            _hasRendered = true;
+            Sync.OnSyncStatusChanged += OnSyncStatusChanged;
+            await LoadDataAsync();
+            StateHasChanged();
+        }
+    }
+
+    private async Task LoadDataAsync()
+    {
+        var all = await InspectionService.GetAllInspectionsAsync();
+        _inspections = all.OrderByDescending(i => i.CreatedAt).ToList();
+        _draftCount = all.Count(i => i.Status == InspectionStatus.Draft);
+        var today = DateTime.UtcNow.Date;
+        _completedTodayCount = all.Count(i => i.Status != InspectionStatus.Draft && i.CompletedAt?.Date == today);
+        _loaded = true;
+    }
+
+    private void StartNewInspection()
+    {
+        Navigation.NavigateTo("/inspection/new");
+    }
+
+    private void NavigateToInspection(InspectionReport inspection)
+    {
+        if (inspection.Status == InspectionStatus.Draft)
+            Navigation.NavigateTo($"/inspection/{inspection.Id}");
+        else
+            Navigation.NavigateTo($"/inspection/{inspection.Id}/detail");
+    }
+
+    private async Task SyncNow()
+    {
+        _isSyncing = true;
+        StateHasChanged();
+        try
+        {
+            await Sync.SyncAsync();
+            await LoadDataAsync();
+        }
+        finally
+        {
+            _isSyncing = false;
+            StateHasChanged();
+        }
+    }
+
+    private string StatusBadgeClass(InspectionStatus status) => status switch
+    {
+        InspectionStatus.Draft => "badge--gray",
+        InspectionStatus.Completed => "badge--blue",
+        InspectionStatus.Synced => "badge--green",
+        _ => ""
+    };
+
+    private void OnSyncStatusChanged()
+    {
+        InvokeAsync(StateHasChanged);
+    }
+
+    public void Dispose()
+    {
+        Sync.OnSyncStatusChanged -= OnSyncStatusChanged;
