    private bool _loaded;
    private bool _hasRendered;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && !_hasRendered)
        {
            _hasRendered = true;
            await LoadSitesAsync();
            StateHasChanged();
        }
    }

    private async Task LoadSitesAsync()
    {
        _sites = await Db.GetAllAsync<ConstructionSite>("sites");
        _loaded = true;
    }

    private void ToggleForm()
    {
        _showForm = !_showForm;
        _errorMessage = "";
        if (!_showForm)
        {
            _newName = "";
            _newAddress = "";
        }
    }

    private async Task SaveSite()
    {
        _errorMessage = "";

        if (string.IsNullOrWhiteSpace(_newName))
        {
            _errorMessage = "Site name is required.";
            return;
        }

        _isSaving = true;
        StateHasChanged();

        try
        {
            var site = new ConstructionSite
            {
                Id = Guid.NewGuid(),
                Name = _newName.Trim(),
                Address = _newAddress.Trim()
            };

            await Db.PutAsync("sites", site);
            _sites.Add(site);
            _newName = "";
            _newAddress = "";
            _showForm = false;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to save: {ex.Message}";
        }
        finally
        {
            _isSaving = false;
        }
    }
}

