        <input id="inspector-name" class="form-input" type="text" @bind="_inspectorName" placeholder="Your name" />
    </div>

    @if (!string.IsNullOrEmpty(_errorMessage))
    {
        <div class="form-error">@_errorMessage</div>
    }

    <button class="btn btn--primary btn--large btn--full" @onclick="StartInspection" disabled="@_isSubmitting">
        @(_isSubmitting ? "Creating…" : "Start Inspection")
    </button>
</div>

@code {
    private List<ConstructionSite> _sites = new();
    private string _selectedSiteId = "";
    private string _newSiteName = "";
    private string _newSiteAddress = "";
    private string _inspectorName = "";
    private string _errorMessage = "";
    private bool _isSubmitting;
    private bool _hasRendered;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && !_hasRendered)
        {
            _hasRendered = true;
            _sites = await Db.GetAllAsync<ConstructionSite>("sites");
            StateHasChanged();
        }
    }

    private async Task StartInspection()
    {
        _errorMessage = "";

        if (string.IsNullOrWhiteSpace(_inspectorName))
        {
            _errorMessage = "Please enter an inspector name.";
            return;
        }

        string siteId;
        string siteName;

        if (_selectedSiteId == "__new__")
        {
            if (string.IsNullOrWhiteSpace(_newSiteName))
            {
                _errorMessage = "Please enter a site name.";
                return;
            }

            var newSite = new ConstructionSite
            {
                Id = Guid.NewGuid(),
                Name = _newSiteName.Trim(),
                Address = _newSiteAddress.Trim()
            };

            await Db.PutAsync("sites", newSite);
            siteId = newSite.Id.ToString();
            siteName = newSite.Name;
        }
        else if (!string.IsNullOrEmpty(_selectedSiteId))
        {
            var site = _sites.FirstOrDefault(s => s.Id.ToString() == _selectedSiteId);
            if (site == null)
            {
                _errorMessage = "Please select a valid site.";
                return;
            }
            siteId = site.Id.ToString();
            siteName = site.Name;
        }
        else
        {
            _errorMessage = "Please select a site or add a new one.";
            return;
        }

        _isSubmitting = true;
        StateHasChanged();

        try
        {
            var report = await InspectionService.CreateInspectionAsync(siteId, siteName, _inspectorName.Trim());
            Navigation.NavigateTo($"/inspection/{report.Id}");
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to create inspection: {ex.Message}";
            _isSubmitting = false;
        }
    }
}

