@code {
    [Parameter] public string Id { get; set; } = "";

    private InspectionReport? _report;
    private HashSet<string> _collapsedCategories = new();
    private HashSet<Guid> _expandedNotes = new();
    private ElementReference _fileInput;
    private Timer? _debounceTimer;
    private bool _isCompleting;
    private bool _hasRendered;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && !_hasRendered)
        {
            _hasRendered = true;
            if (Guid.TryParse(Id, out var guid))
            {
                _report = await InspectionService.GetInspectionAsync(guid);
            }
            StateHasChanged();
        }
    }

    private int CheckedCount() => _report?.Items.Count(i => i.IsChecked) ?? 0;

    private double ProgressPercent()
    {
        if (_report == null || _report.Items.Count == 0) return 0;
        return (double)CheckedCount() / _report.Items.Count * 100;
    }

    private bool IsCategoryExpanded(string category) => !_collapsedCategories.Contains(category);

    private void ToggleCategory(string category)
    {
        if (!_collapsedCategories.Remove(category))
            _collapsedCategories.Add(category);
    }

    private void ToggleItem(ChecklistItem item)
    {
        item.IsChecked = !item.IsChecked;
        ScheduleDebouncedSave();
    }

    private void ToggleNotes(Guid itemId)
    {
        if (!_expandedNotes.Remove(itemId))
            _expandedNotes.Add(itemId);
    }

    private void OnNotesChanged(ChecklistItem item, ChangeEventArgs e)
    {
        item.Notes = e.Value?.ToString() ?? "";
        ScheduleDebouncedSave();
    }

    private void OnGeneralNotesChanged(ChangeEventArgs e)
    {
        if (_report != null)
        {
            _report.Notes = e.Value?.ToString() ?? "";
            ScheduleDebouncedSave();
        }
    }

    private void ScheduleDebouncedSave()
    {
        _debounceTimer?.Dispose();
        _debounceTimer = new Timer(async _ =>
        {
            try
            {
                if (_report != null)
                {
                    await InspectionService.SaveInspectionAsync(_report);
                }
            }
            catch
            {
                // Save failed silently; will retry on next change
            }
        }, null, TimeSpan.FromSeconds(1), Timeout.InfiniteTimeSpan);
    }

    private async Task TriggerPhotoCapture()
    {
        await JS.InvokeVoidAsync("eval", "document.querySelector('.hidden-input').click()");
    }

    private async Task OnPhotoSelected(ChangeEventArgs e)
    {
        if (_report == null) return;

        try
        {
            var base64 = await JS.InvokeAsync<string>("siteInspector.resizeAndReadImage", _fileInput, 1024, 0.8);

            if (!string.IsNullOrEmpty(base64))
            {
                var photo = new PhotoAttachment
                {
                    Id = Guid.NewGuid(),
                    FileName = $"photo_{DateTime.UtcNow:yyyyMMdd_HHmmss}.jpg",
                    CapturedAt = DateTime.UtcNow,
                    Base64Data = base64
                };

                _report.Photos.Add(photo);
                ScheduleDebouncedSave();
                StateHasChanged();
            }
        }
        catch
        {
            // Photo capture failed silently
        }
    }

    private async Task CompleteInspection()
    {
        if (_report == null) return;

        _isCompleting = true;
        StateHasChanged();

        try
        {
            _debounceTimer?.Dispose();
            await InspectionService.SaveInspectionAsync(_report);
            await InspectionService.CompleteInspectionAsync(_report.Id);
            Navigation.NavigateTo($"/inspection/{_report.Id}/detail");
        }
        catch
        {
            _isCompleting = false;
            StateHasChanged();
        }
    }

    private string SeverityBadgeClass(Severity severity) => severity switch
    {
        Severity.Info => "badge--blue",
        Severity.Warning => "badge--orange",
        Severity.Critical => "badge--red",
        _ => ""
    };

    public void Dispose()
    {
        _debounceTimer?.Dispose();
    }
}

