--- a/dev/null
+++ b/tmp/sv-2f2abdfc3d914274b3858e3a404c1946/SiteInspector/src/SiteInspector.Client/Pages/InspectionChecklist.razor
@@ -1,0 +1,269 @@
+@page "/inspection/{Id}"
+@inject InspectionService InspectionService
+@inject NavigationManager Navigation
+@inject IJSRuntime JS
+@implements IDisposable
+
+<PageTitle>Inspection - Site Inspector</PageTitle>
+
+@if (_report == null)
+{
+    <div class="page-loading">
+        <p class="loading-text">Loading inspection…</p>
+    </div>
+}
+else
+{
+    <div class="checklist-page">
+        <header class="checklist-header">
+            <h2 class="checklist-header__site">@_report.SiteName</h2>
+            <div class="progress-bar">
+                <div class="progress-bar__fill" style="width: @ProgressPercent()%"></div>
+            </div>
+            <span class="progress-bar__text">@CheckedCount() of @_report.Items.Count items checked</span>
+        </header>
+
+        @if (_report.Photos.Count > 0)
+        {
+            <div class="photo-strip">
+                @foreach (var photo in _report.Photos)
+                {
+                    <div class="photo-strip__thumb">
+                        <img src="data:image/jpeg;base64,@photo.Base64Data" alt="@photo.FileName" />
+                    </div>
+                }
+            </div>
+        }
+
+        <div class="checklist-groups">
+            @foreach (var group in _report.Items.GroupBy(i => i.Category))
+            {
+                var category = group.Key;
+                var isExpanded = IsCategoryExpanded(category);
+
+                <section class="checklist-category">
+                    <button class="checklist-category__header" @onclick="() => ToggleCategory(category)">
+                        <span class="checklist-category__title">@category</span>
+                        <span class="checklist-category__chevron @(isExpanded ? "checklist-category__chevron--open" : "")">
+                            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="6 9 12 15 18 9"/></svg>
+                        </span>
+                    </button>
+
+                    @if (isExpanded)
+                    {
+                        <div class="checklist-category__items">
+                            @foreach (var item in group)
+                            {
+                                var localItem = item;
+                                var showNotes = _expandedNotes.Contains(localItem.Id);
+
+                                <div class="checklist-item @(localItem.IsChecked ? "checklist-item--checked" : "")">
+                                    <div class="checklist-item__row" @onclick="() => ToggleItem(localItem)">
+                                        <span class="checklist-item__checkbox @(localItem.IsChecked ? "checklist-item__checkbox--on" : "")">
+                                            @if (localItem.IsChecked)
+                                            {
+                                                <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="20 6 9 17 4 12"/></svg>
+                                            }
+                                        </span>
+                                        <span class="checklist-item__desc">@localItem.Description</span>
+                                        <span class="badge @SeverityBadgeClass(localItem.Severity)">@localItem.Severity</span>
+                                        <button class="checklist-item__notes-btn" @onclick="() => ToggleNotes(localItem.Id)" @onclick:stopPropagation="true" title="Notes">
+                                            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>
+                                        </button>
+                                    </div>
+
+                                    @if (showNotes)
+                                    {
+                                        <div class="checklist-item__notes-area">
+                                            <textarea class="form-textarea" rows="2" placeholder="Add notes…"
+                                                      value="@localItem.Notes"
+                                                      @oninput="e => OnNotesChanged(localItem, e)"></textarea>
+                                        </div>
+                                    }
+                                </div>
+                            }
+                        </div>
+                    }
+                </section>
+            }
+        </div>
+
+        <div class="form-group checklist-general-notes">
+            <label class="form-label">General Notes</label>
+            <textarea class="form-textarea" rows="3" placeholder="Overall inspection notes…"
+                      value="@_report.Notes"
+                      @oninput="OnGeneralNotesChanged"></textarea>
+        </div>
+
+        <div class="checklist-actions">
+            <button class="btn btn--primary btn--large btn--full"
+                    @onclick="CompleteInspection"
+                    disabled="@(CheckedCount() == 0 || _isCompleting)">
+                @(_isCompleting ? "Completing…" : "Complete Inspection")
+            </button>
+        </div>
+
+        <input type="file" accept="image/*" capture="environment" @ref="_fileInput"
+               class="hidden-input" @onchange="OnPhotoSelected" />
+
+        <button class="fab" @onclick="TriggerPhotoCapture" title="Add Photo">
+            <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="3" width="18" height="18" rx="2" ry="2"/><circle cx="12" cy="13" r="4"/><path d="M5 7h.01"/></svg>
+        </button>
+    </div>
+}
+
+@code {
+    [Parameter] public string Id { get; set; } = "";
+
+    private InspectionReport? _report;
+    private HashSet<string> _collapsedCategories = new();
+    private HashSet<Guid> _expandedNotes = new();
+    private ElementReference _fileInput;
+    private Timer? _debounceTimer;
+    private bool _isCompleting;
+    private bool _hasRendered;
+
+    protected override async Task OnAfterRenderAsync(bool firstRender)
+    {
+        if (firstRender && !_hasRendered)
+        {
+            _hasRendered = true;
+            if (Guid.TryParse(Id, out var guid))
+            {
+                _report = await InspectionService.GetInspectionAsync(guid);
+            }
+            StateHasChanged();
+        }
+    }
+
+    private int CheckedCount() => _report?.Items.Count(i => i.IsChecked) ?? 0;
+
+    private double ProgressPercent()
+    {
+        if (_report == null || _report.Items.Count == 0) return 0;
+        return (double)CheckedCount() / _report.Items.Count * 100;
+    }
+
+    private bool IsCategoryExpanded(string category) => !_collapsedCategories.Contains(category);
+
+    private void ToggleCategory(string category)
+    {
+        if (!_collapsedCategories.Remove(category))
+            _collapsedCategories.Add(category);
+    }
+
+    private void ToggleItem(ChecklistItem item)
+    {
+        item.IsChecked = !item.IsChecked;
+        ScheduleDebouncedSave();
+    }
+
+    private void ToggleNotes(Guid itemId)
+    {
+        if (!_expandedNotes.Remove(itemId))
+            _expandedNotes.Add(itemId);
+    }
+
+    private void OnNotesChanged(ChecklistItem item, ChangeEventArgs e)
+    {
+        item.Notes = e.Value?.ToString() ?? "";
+        ScheduleDebouncedSave();
+    }
+
+    private void OnGeneralNotesChanged(ChangeEventArgs e)
+    {
+        if (_report != null)
+        {
+            _report.Notes = e.Value?.ToString() ?? "";
+            ScheduleDebouncedSave();
+        }
+    }
+
+    private void ScheduleDebouncedSave()
+    {
+        _debounceTimer?.Dispose();
+        _debounceTimer = new Timer(async _ =>
+        {
+            try
+            {
+                if (_report != null)
+                {
+                    await InspectionService.SaveInspectionAsync(_report);
+                }
+            }
+            catch
+            {
+                // Save failed silently; will retry on next change
+            }
+        }, null, TimeSpan.FromSeconds(1), Timeout.InfiniteTimeSpan);
+    }
+
+    private async Task TriggerPhotoCapture()
+    {
+        await JS.InvokeVoidAsync("eval", "document.querySelector('.hidden-input').click()");
+    }
+
+    private async Task OnPhotoSelected(ChangeEventArgs e)
+    {
+        if (_report == null) return;
+
+        try
+        {
+            var base64 = await JS.InvokeAsync<string>("siteInspector.resizeAndReadImage", _fileInput, 1024, 0.8);
+
+            if (!string.IsNullOrEmpty(base64))
+            {
+                var photo = new PhotoAttachment
+                {
+                    Id = Guid.NewGuid(),
+                    FileName = $"photo_{DateTime.UtcNow:yyyyMMdd_HHmmss}.jpg",
+                    CapturedAt = DateTime.UtcNow,
+                    Base64Data = base64
+                };
+
+                _report.Photos.Add(photo);
+                ScheduleDebouncedSave();
+                StateHasChanged();
+            }
+        }
+        catch
+        {
+            // Photo capture failed silently
+        }
+    }
+
+    private async Task CompleteInspection()
+    {
+        if (_report == null) return;
+
+        _isCompleting = true;
+        StateHasChanged();
+
+        try
+        {
+            _debounceTimer?.Dispose();
+            await InspectionService.SaveInspectionAsync(_report);
+            await InspectionService.CompleteInspectionAsync(_report.Id);
+            Navigation.NavigateTo($"/inspection/{_report.Id}/detail");
+        }
+        catch
+        {
+            _isCompleting = false;
+            StateHasChanged();
+        }
+    }
+
+    private string SeverityBadgeClass(Severity severity) => severity switch
+    {
+        Severity.Info => "badge--blue",
+        Severity.Warning => "badge--orange",
+        Severity.Critical => "badge--red",
+        _ => ""
+    };
+
+    public void Dispose()
+    {
+        _debounceTimer?.Dispose();
+    }
+}
+

