+@page "/sites"
+@inject IndexedDbService Db
+
+<PageTitle>Sites - Site Inspector</PageTitle>
+
+<div class="sites-page">
+    <div class="sites-page__header">
+        <h2 class="section-title">Construction Sites</h2>
+        <button class="btn btn--outline btn--small" @onclick="ToggleForm">
+            @(_showForm ? "Cancel" : "+ Add Site")
+        </button>
+    </div>
+
+    @if (_showForm)
+    {
+        <div class="site-form">
+            <div class="form-group">
+                <label class="form-label" for="site-name">Site Name</label>
+                <input id="site-name" class="form-input" type="text" @bind="_newName" placeholder="e.g. Downtown Tower" />
+            </div>
+            <div class="form-group">
+                <label class="form-label" for="site-address">Address</label>
+                <input id="site-address" class="form-input" type="text" @bind="_newAddress" placeholder="123 Main St" />
+            </div>
+            @if (!string.IsNullOrEmpty(_errorMessage))
+            {
+                <div class="form-error">@_errorMessage</div>
+            }
+            <button class="btn btn--primary" @onclick="SaveSite" disabled="@_isSaving">
+                @(_isSaving ? "Saving…" : "Save Site")
+            </button>
+        </div>
+    }
+
+    @if (!_loaded)
+    {
+        <p class="loading-text">Loading sites…</p>
+    }
+    else if (_sites.Count == 0 && !_showForm)
+    {
+        <p class="empty-text">No sites saved yet. Tap "+ Add Site" to create one.</p>
+    }
+    else
+    {
+        <div class="sites-list">
+            @foreach (var site in _sites)
+            {
+                <div class="site-card">
+                    <span class="site-card__name">@site.Name</span>
+                    @if (!string.IsNullOrWhiteSpace(site.Address))
+                    {
+                        <span class="site-card__address">@site.Address</span>
+                    }
+                </div>
+            }
+        </div>
+    }
+</div>
+
+@code {
+    private List<ConstructionSite> _sites = new();
+    private bool _showForm;
+    private string _newName = "";
+    private string _newAddress = "";
+    private string _errorMessage = "";
+    private bool _isSaving;
+    private bool _loaded;
+    private bool _hasRendered;
+
+    protected override async Task OnAfterRenderAsync(bool firstRender)
+    {
+        if (firstRender && !_hasRendered)
+        {
+            _hasRendered = true;
+            await LoadSitesAsync();
+            StateHasChanged();
+        }
+    }
+
+    private async Task LoadSitesAsync()
+    {
+        _sites = await Db.GetAllAsync<ConstructionSite>("sites");
+        _loaded = true;
+    }
+
+    private void ToggleForm()
+    {
+        _showForm = !_showForm;
+        _errorMessage = "";
+        if (!_showForm)
+        {
+            _newName = "";
+            _newAddress = "";
+        }
+    }
+
+    private async Task SaveSite()
+    {
+        _errorMessage = "";
+
+        if (string.IsNullOrWhiteSpace(_newName))
+        {
+            _errorMessage = "Site name is required.";
+            return;
+        }
+
+        _isSaving = true;
+        StateHasChanged();
+
+        try
+        {
+            var site = new ConstructionSite
+            {
+                Id = Guid.NewGuid(),
+                Name = _newName.Trim(),
+                Address = _newAddress.Trim()
+            };
+
+            await Db.PutAsync("sites", site);
+            _sites.Add(site);
+            _newName = "";
+            _newAddress = "";
+            _showForm = false;
+        }
+        catch (Exception ex)
+        {
+            _errorMessage = $"Failed to save: {ex.Message}";
+        }
+        finally
+        {
+            _isSaving = false;
+        }
+    }
+}
+

